  ?company wdt:P571 ?inceptionYear.
}
ORDER BY ASC(?inceptionYear)

SELECT ?desert ?desertLabel ?area WHERE {
  VALUES ?desert {wd:Q2736 wd:Q4779} # Sahara Desert and Arabian Desert
  ?desert wdt:P2046 ?area. # Property for area
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}
ORDER BY DESC(?area)

SELECT ?person ?personLabel ?lifespan WHERE {
  VALUES ?person { wd:Q36864844 wd:Q95074 wd:Q95073 } # Bellatrix Lestrange, Sirius Black, and Regulus Black
  ?person wdt:P569 ?birthDate.
  ?person wdt:P570 ?deathDate.
  BIND(YEAR(?deathDate) - YEAR(?birthDate) AS ?lifespan)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}
ORDER BY DESC(?lifespan)

SELECT ?lake ?lakeLabel ?area WHERE {
  ?lake wdt:P469 wd:Q1537;  # Q1537 represents the Great Lakes
        wdt:P2046 ?area.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

